import React, { useState, useEffect } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, Loader2, Search } from 'lucide-react';
import { calcularDistanciaReal } from '../utils/shippingService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const COORDS_LOCAL = { lat: -26.732479, lon: -65.267028 };

const PanelCliente = () => {
  const [pestañaActiva, setPestañaActiva] = useState('tienda'); // tienda, proceso, historial
  const [ofertas, setOfertas] = useState([]);
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]); // Todos los pedidos
  
  // Estados de ubicación
  const [busqueda, setBusqueda] = useState("");
  const [sugerencias, setSugerencias] = useState([]);
  const [distanciaReal, setDistanciaReal] = useState(0);

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acc = [];
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      acc = [...acc, ...ofs.map(o => ({ ...o, nombreLocal: l.nombre, localId: l.id }))];
    });
    setOfertas(acc);
    
    // Cargar pedidos guardados si existen
    const historial = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    setPedidos(historial);
  }, []);

  const handlePagoExitoso = (totalPagado) => {
    const nuevoPedido = { 
      id: `PED-${Date.now()}`, 
      total: totalPagado, 
      items: [...cart],
      fecha: new Date().toLocaleString(),
      estado: 'proceso', // proceso, completado
      distancia: distanciaReal
    };
    const nuevosPedidos = [nuevoPedido, ...pedidos];
    setPedidos(nuevosPedidos);
    localStorage.setItem('historial-pedidos', JSON.stringify(nuevosPedidos));
    setCart([]);
    setPestañaActiva('proceso'); // Salto automático al seguimiento
  };

  // Filtrado de pedidos por estado
  const pedidosEnProceso = pedidos.filter(p => p.estado === 'proceso');
  const pedidosRealizados = pedidos.filter(p => p.estado === 'completado');

  return (
    <div style={containerStyle}>
      {/* SIDEBAR DE NAVEGACIÓN */}
      <div style={sidebarStyle}>
        <h2 style={logoStyle}>OfertasApp</h2>
        <button onClick={() => setPestañaActiva('tienda')} style={pestañaActiva === 'tienda' ? navBtnActive : navBtn}>
          <ShoppingBag size={20} /> Hacer mi pedido
        </button>
        <button onClick={() => setPestañaActiva('proceso')} style={pestañaActiva === 'proceso' ? navBtnActive : navBtn}>
          <Clock size={20} /> Pedidos en proceso 
          {pedidosEnProceso.length > 0 && <span style={badgeStyle}>{pedidosEnProceso.length}</span>}
        </button>
        <button onClick={() => setPestañaActiva('historial')} style={pestañaActiva === 'historial' ? navBtnActive : navBtn}>
          <CheckCircle size={20} /> Pedidos realizados
        </button>
      </div>

      {/* CONTENIDO DINÁMICO */}
      <div style={contentStyle}>
        {pestañaActiva === 'tienda' && (
          <div style={viewContainer}>
            <div style={{ flex: 1 }}>
              <h2 style={titleStyle}>Explorar Ofertas</h2>
              {/* Aquí va tu buscador de direcciones y el grid de ofertas */}
              <div style={gridStyle}>
                {ofertas.map(o => (
                  <div key={o.id} style={cardStyle}>
                    <img src={o.imagen} style={imgStyle} alt="" />
                    <div style={{padding:'15px'}}>
                      <small>{o.nombreLocal}</small>
                      <h4>{o.producto}</h4>
                      <button onClick={() => setCart([...cart, o])} style={btnAddToCart}>Agregar ${o.precioNuevo}</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div style={{ width: '350px' }}>
              <Carrito cart={cart} setCart={setCart} distanciaReal={distanciaReal} onCheckout={handlePagoExitoso} />
            </div>
          </div>
        )}

        {pestañaActiva === 'proceso' && (
          <div style={centeredView}>
            <h2>Seguimiento en Tiempo Real</h2>
            {pedidosEnProceso.length === 0 ? (
              <p>No tienes pedidos activos ahora mismo.</p>
            ) : (
              pedidosEnProceso.map(p => <SeguimientoPedido key={p.id} pedido={p} />)
            )}
          </div>
        )}

        {pestañaActiva === 'historial' && (
          <div style={centeredView}>
            <h2>Tu Historial de Compras</h2>
            <table style={tableStyle}>
              <thead>
                <tr style={headerTable}>
                  <th>ID Pedido</th>
                  <th>Fecha</th>
                  <th>Total</th>
                  <th>Estado</th>
                </tr>
              </thead>
              <tbody>
                {pedidos.map(p => (
                  <tr key={p.id} style={rowTable}>
                    <td>#{p.id.slice(-6)}</td>
                    <td>{p.fecha}</td>
                    <td>${p.total}</td>
                    <td><span style={p.estado === 'proceso' ? tagProceso : tagCompletado}>{p.estado}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

// --- ESTILOS PROFESIONALES ---
const containerStyle = { display: 'flex', minHeight: '100vh', background: '#f8fafc' };
const sidebarStyle = { width: '260px', background: '#1e293b', color: 'white', padding: '30px 20px', display: 'flex', flexDirection: 'column', gap: '10px' };
const logoStyle = { fontSize: '1.5rem', fontWeight: 'bold', color: '#e67e22', marginBottom: '30px' };
const navBtn = { display: 'flex', alignItems: 'center', gap: '12px', padding: '12px 15px', background: 'transparent', border: 'none', color: '#cbd5e1', cursor: 'pointer', borderRadius: '10px', textAlign: 'left', transition: '0.3s' };
const navBtnActive = { ...navBtn, background: '#334155', color: 'white' };
const badgeStyle = { background: '#e67e22', color: 'white', fontSize: '0.7rem', padding: '2px 6px', borderRadius: '50%', marginLeft: 'auto' };
const contentStyle = { flex: 1, padding: '40px' };
const viewContainer = { display: 'flex', gap: '30px' };
const titleStyle = { marginBottom: '20px', fontSize: '1.8rem', color: '#1e293b' };
const centeredView = { maxWidth: '800px', margin: '0 auto' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '20px' };
const cardStyle = { background: 'white', borderRadius: '15px', overflow: 'hidden', border: '1px solid #e2e8f0' };
const imgStyle = { width: '100%', height: '140px', objectFit: 'cover' };
const btnAddToCart = { width: '100%', padding: '10px', background: '#1e293b', color: 'white', border: 'none', cursor: 'pointer', marginTop: '10px', borderRadius: '8px' };
const tableStyle = { width: '100%', borderCollapse: 'collapse', marginTop: '20px', background: 'white', borderRadius: '15px', overflow: 'hidden' };
const headerTable = { background: '#f1f5f9', textAlign: 'left' };
const rowTable = { borderBottom: '1px solid #f1f5f9' };
const tagProceso = { background: '#fff7ed', color: '#c2410c', padding: '4px 8px', borderRadius: '6px', fontSize: '0.8rem' };
const tagCompletado = { background: '#f0fdf4', color: '#166534', padding: '4px 8px', borderRadius: '6px', fontSize: '0.8rem' };

export default PanelCliente;
